import android.content.Context;
import android.content.SharedPreferences;

public class LoginRepository {

    private static final String PREFS_FILE_NAME = "user_login_preferences";
    private static final String EMAIL_KEY = "user_email";
    private static final String AUTH_TOKEN_KEY = "auth_token";

    private final SharedPreferences sharedPreferences;

    public LoginRepository(Context context) {
        sharedPreferences = context.getSharedPreferences(PREFS_FILE_NAME, Context.MODE_PRIVATE);
    }

    public void saveUserCredentials(String email, String authToken) {
        SharedPreferences.Editor editor = sharedPreferences.edit();
        editor.putString(EMAIL_KEY, email);
        editor.putString(AUTH_TOKEN_KEY, authToken);
        editor.apply();
    }

    public String getUserEmail() {
        return sharedPreferences.getString(EMAIL_KEY, null);
    }

    public String getAuthToken() {
        return sharedPreferences.getString(AUTH_TOKEN_KEY, null);
    }

    public boolean isLoggedIn() {
        return getUserEmail() != null && getAuthToken() != null;
    }
}